ivity":"March 2025: Participated in $225M GPU credit facility for Crusoe (with Upper90, BCI, King Street, LMI, ORIX).","key_partnerships":"Upper90 (Crusoe deal), Crusoe (borrower), KKR (FS KKR Capital co-investment vehicle)","email_pattern":"initial+last@fsinvestments.com (guessed)"},"recent_news":["March 2025: Participated in $225M Crusoe GPU credit facility","March 2024: Hired Lisa Opoku as COO and Stephen Tisdalle as CMO","February 2023: Merged with Portfolio Advisors ($73B+ combined AUM)"],"qualification_notes":"LENDER/CO-INVESTOR potential — already participated in GPU-collateralized credit (Crusoe deal). $76B AUM means they have capital to deploy. Not a GPU operator. Approach as potential co-lender or LP."}','2026-03-21 02:49:33');
INSERT INTO research_notes VALUES('f1f9222f-3962-4443-9968-48f4960b1d33','a86bfe09-5c50-4c98-b3d6-b42e1b595cf2','https://libertymutualinvestments.com',unistr('INSTITUTIONAL CO-LENDER potential — already deployed capital in GPU-collateralized credit (Crusoe). Insurance/investment arm with long-term capital looking for yield. Adam Winn (Global Alternatives) is the most relevant contact for private credit/GPU asset discussions.\u000a\u000aGPU scale: N/A — insurance investment arm managing LMG''s ~$100B+ investment portfolio.\u000a\u000aFunding: N/A — insurance company asset manager.\u000a\u000aFinancing: March 2025: Participated in $225M Crusoe GPU credit facility. Also: strategic partnership with Ara Partners (energy/infrastructure VC). HQ: 157 Berkeley St, Boston MA 02116. Phone: 617-357-9500.\u000a\u000aPartners: Upper90 (Crusoe deal), Ara Partners (energy infrastructure), Liberty Mutual Insurance (parent)\u000a\u000aRecent news:\u000a• March 2025: Participated in $225M Crusoe GPU credit facility (with Upper90, BCI, FS, King Street, ORIX)\u000a• Formed strategic partnership with Ara Partners for energy/infrastructure investing\u000a• Managing $72B+ in liquid markets (Felton) and private alternatives (Winn)'),'{"name":"Liberty Mutual Investments","priority":"C","domain":"libertymutualinvestments.com","contacts":[{"name":"Vlad Y. Barbalat","title":"EVP & CIO; President, Liberty Mutual Investments","email":"vlad.barbalat@lmi.com","linkedin":"https://www.linkedin.com/in/vlad-barbalat","source":"ZoomInfo (v***@lmi.com confirmed), LMI website","confidence":"high","email_confidence":"medium — ZoomInfo confirms v***@lmi.com (lmi.com domain, not libertymutualinvestments.com)"},{"name":"Christopher Felton","title":"Head of Global Liquid Markets ($72B AUM)","email":"christopher.felton@lmi.com","linkedin":"https://www.linkedin.com/company/liberty-mutual-investments","source":"LMI website, LMI who-we-are page","confidence":"high","email_confidence":"low"},{"name":"Adam Winn","ti